<template><section class="page"><div class="toolbar"><el-input v-model="q" placeholder="搜索运单号/订单号" style="max-width:260px" @keyup.enter="load"/><el-button type="primary" @click="load">查询</el-button><el-button @click="createDemo">创建演示运单</el-button></div><div class="panel"><el-table :data="rows" v-loading="loading" @row-click="open"><el-table-column prop="tracking_no" label="运单号"/><el-table-column prop="business_order_no" label="业务订单"/><el-table-column prop="carrier_code" label="物流商"/><el-table-column label="当前状态"><template #default="s"><el-tag :type="statusType(s.row.current_status)">{{statusText[s.row.current_status]}}</el-tag></template></el-table-column><el-table-column prop="has_open_anomaly" label="异常"><template #default="s"><el-tag :type="s.row.has_open_anomaly?'danger':'success'">{{s.row.has_open_anomaly?'有':'无'}}</el-tag></template></el-table-column></el-table></div><el-drawer v-model="show" size="60%" title="运单详情"><template v-if="detail.shipment"><h3>{{detail.shipment.tracking_no}} · {{statusText[detail.shipment.current_status]}}</h3><el-button type="warning" @click="reconcile">发起对账</el-button><div class="timeline panel"><div v-for="e in detail.events" :key="e.id" class="timeline-item" :class="{invalid:e.validation_status!=='VALID',reconciliation:e.source==='RECONCILIATION'}"><strong>{{statusText[e.normalized_status]}} / {{e.raw_status}}</strong><p class="muted">eventTime {{formatTime(e.event_time)}} · receivedTime {{formatTime(e.received_time)}} · {{e.location}}</p><el-tag v-if="e.late_arrival" type="warning">迟到</el-tag><el-tag v-if="e.validation_status!=='VALID'" type="danger">{{e.validation_status}}</el-tag><el-tag v-if="e.source==='RECONCILIATION'" type="success">对账补入</el-tag><p>{{e.description}}</p></div></div></template></el-drawer></section></template>
<script setup lang="ts">import { onMounted, ref } from 'vue'; import { http } from '../api/http'; import { formatTime,statusText,statusType } from '../utils/status'; const q=ref(''); const rows=ref<any[]>([]); const loading=ref(false); const show=ref(false); const detail=ref<any>({}); async function load(){loading.value=true; try{rows.value=await http.get('/shipments',{params:{q:q.value}})} finally{loading.value=false}} async function open(row:any){detail.value=await http.get('/shipments/'+row.id); show.value=true} async function createDemo(){await http.post('/shipments',{carrierCode:'MOCK_A',trackingNo:'A'+Date.now(),businessOrderNo:'ORDER-'+Date.now()}); await load()} async function reconcile(){await http.post('/reconciliation/shipments/'+detail.value.shipment.id); detail.value=await http.get('/shipments/'+detail.value.shipment.id); await load()} onMounted(load)</script>
